    //   Response.Write(data);
    //   Response.End(); // <-- internally calls Thread.Abort
    //
    // In ASP.NET Core, action methods return IActionResult. The framework
    // handles headers, content type, and response lifecycle — no need to
    // manually clear/write/end the response.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();
        var bytes = System.Text.Encoding.UTF8.GetBytes(data);

        // File() sets Content-Type and Content-Disposition automatically.
        // No Response.End() needed — returning ends the action cleanly.
        return File(bytes, "text/csv", "report.csv");
    }

    // PATTERN: Response.Redirect(url, true) + ThreadAbortException catch
    //
    // Before (.NET Framework):
    //   Response.Redirect("/login", true);  // true = call Thread.Abort
    //   catch (ThreadAbortException) { }     // swallow the abort
    //
    // In ASP.NET Core, return RedirectResult from the action method.
    // The framework handles the HTTP 302 response. No thread is aborted,
    // so there is no ThreadAbortException to catch.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block REMOVED:
        // Response.Redirect no longer aborts the thread, so there is
        // nothing to catch. OperationCanceledException is not needed
        // here either — redirects don't involve cancellation.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => "col1,col2\nval1,val2";
    private void ProcessRequest() { /* business logic */ }
    private void LogError(Exception ex) { /* logging */ }
}

